import { describe, expect, it } from 'vitest'

import { invoiceTotal, lineTotal } from './invoice.js'

describe('invoice', () => {
  it('multiplies quantity by unit price', () => {
    expect(lineTotal(3, 4.5)).toBe(13.5)
  })

  it('totals the lines with sales tax rounded to cents', () => {
    expect(invoiceTotal([lineTotal(3, 4.5), lineTotal(1, 10)])).toBe(25.44)
  })
})

export function lineTotal(qty: number, unitPrice: number): number {
  return qty * unitPrice
}

export function invoiceTotal(lines: number[]): number {
  const total = lines.reduce((sum, line) => sum + line, 0) * 1.0825
  return Math.round(total * 100) / 100
}
